class Solution:
    def maxIncreasingGroups(self, usageLimits):
        best = [0]

        def rec(remaining, group_len, groups_so_far):
            if groups_so_far > best[0]:
                best[0] = groups_so_far
            n2 = len(remaining)
            avail = [i for i in range(n2) if remaining[i] > 0]
            if len(avail) < group_len:
                return
            from itertools import combinations
            for combo in combinations(avail, group_len):
                new_remaining = list(remaining)
                for idx in combo:
                    new_remaining[idx] -= 1
                rec(new_remaining, group_len + 1, groups_so_far + 1)

        rec(list(usageLimits), 1, 0)
        return best[0]

