class Solution:
    def maxIncreasingGroups(self, usageLimits):
        limits = sorted(usageLimits)
        groups = 0
        total = 0
        for limit in limits:
            total += limit
            if total >= groups + 1:
                groups += 1
                total -= groups
        return groups

