var maxIncreasingGroups = function(usageLimits) {
    const limits = [...usageLimits].sort((a, b) => a - b);
    let groups = 0;
    let total = 0;
    for (const limit of limits) {
        total += limit;
        if (total >= groups + 1) {
            groups += 1;
            total -= groups;
        }
    }
    return groups;
};
